INSERT INTO quiz_question (id, word_bank_id, contextual_cloze, chinese_translation, correct_answer, distractor1, distractor2, distractor3, explanation_root_affix, explanation_mnemonic, created_at, updated_at) VALUES
('83a38ffe-d4d3-5d58-89c2-5cb1f8126480', 'e550250e-e030-45ce-9f76-810c51406728', 'Valentine''s Day is in ___.', '情人節是在二月。', 'February', 'Monday', 'Summer', 'Evening', 'February 為月份名稱，指二月。', '記住情人節是在二月 (February)。', '2026-07-07 05:19:13', '2026-07-07 05:19:13'),
('112afbde-c403-5fde-a648-a4eb25ac0c6c', '5f95c99e-a872-4370-865d-0e908a86488a', 'Due to his unexpected ___ from the meeting, the team had to postpone the final decision.', '由於他意外地缺席了會議，團隊不得不延後最終決定。', 'absence', 'distance', 'patience', 'benefit', '字首 ab- 表示離開，加上表示狀態的字尾，組合起來就是不在場的意思。', '記住 ab- 有離開的意思，absence 就是離開了原本該在的位置 → 缺席。', '2026-07-06 16:11:00', '2026-07-06 16:11:00'),
('458a762c-1c47-571c-9e32-d067a1917a40', '59b698fa-1ae8-4cb5-93c0-cfe008041255', 'The period of ___ is often characterized by a search for self-identity and independence.', '青春期通常以尋求自我認同與獨立為特徵。', 'adolescence', 'childhood', 'adulthood', 'retirement', 'ad- (向) + lesce (成長) + -ence (名詞字尾) → 走向成長的階段。', 'ad (向) + lesce (成長) + ence (名詞) → 向著成長的過程 → 青春期。', '2026-07-06 17:57:03', '2026-07-06 17:57:03'),
('04bbd857-e3be-58ec-8e0a-78b2dd5ed538', '231026ab-acab-472b-a396-92556260d8db', 'We should go for a walk ___ dinner to help with digestion.', '我們應該在晚餐後去散步以幫助消化。', 'after', 'during', 'beside', 'under', 'after 本身為常用介係詞，無特定單一字根。', '記住 after 代表「在...之後」，例如 after school (放學後)。', '2026-07-06 18:44:54', '2026-07-06 18:44:54'),
('be5ef320-78bf-5178-a19a-df2bd394e8b0', 'c3b74e7c-358e-444e-8450-ddbfb2f1dd72', 'The movie starts at two o''clock in the ___.', '這部電影在下午兩點開始。', 'afternoon', 'morning', 'midnight', 'evening', 'after (在...之後) + noon (中午) → 中午之後的時間。', '記住 after 是「之後」，noon 是「中午」，中午之後就是下午。', '2026-07-06 13:24:18', '2026-07-06 13:24:18'),
('a209fcb7-9501-52e5-8a2a-5737b529a3f0', 'd3b0a3a9-6752-410b-89c4-53965a450f77', 'The massive ___ lay motionless in the murky waters of the Everglades, waiting for its prey to approach.', '那隻巨大的短吻鱷靜靜地待在埃弗格萊茲沼澤混濁的水中，等待著獵物靠近。', 'alligator', 'dolphin', 'eagle', 'hamster', '源自西班牙語 el lagarto，意指「蜥蜴」。', '想像一隻巨大的鱷魚在泥沼中像蜥蜴一樣靜止不動，等待獵物。', '2026-07-06 20:00:18', '2026-07-06 20:00:18'),
('98db8045-f8c2-547f-aa6d-ba785b798648', '4e7ec9ef-7831-4401-854f-1f68c3b2232c', 'To make the dessert more delicious, the chef sprinkled some crushed ___ over the chocolate mousse.', '為了讓甜點更美味，主廚在巧克力慕斯上撒了一些碎杏仁。', 'almonds', 'apples', 'onions', 'peppers', 'almond 為名詞，指杏仁。', 'almond 聽起來像 all money → 買了這麼多杏仁，花掉了所有的錢 (all money) → almond。', '2026-07-06 20:06:26', '2026-07-06 20:06:26'),
('c7eff852-ebae-5343-9f5d-d7f341358ccc', 'c6a5c209-9b8e-47d9-a0b6-bb288d42326a', 'The archeologists discovered the remains of an ___ civilization buried deep under the desert sands.', '考古學家在沙漠深處發現了一個古代文明的遺跡。', 'ancient', 'modern', 'annual', 'various', '來自拉丁語 ''ante'' (在...之前)，表示時間上的久遠。', '想像一個很老的 (ancient) 歷史書，翻開它就能看到古代的文明。', '2026-07-06 21:12:49', '2026-07-06 21:12:49'),
('bdeeb185-a273-5700-bad9-8dca68567f50', '863f960c-9dea-4632-a9cb-3487b5c50eab', 'You ___ a student.', '你是一名學生。', 'are', 'want', 'make', 'take', 'be 動詞，用於第二人稱表示「是」。', 'You → are', '2026-07-05 11:32:46', '2026-07-05 11:32:46'),
('11bb7cd5-0a8f-50c3-a201-989e17f67240', '6caf5415-789b-4962-912b-1129e21aa239', 'The students use crayons to ___ the pictures.', '學生們用蠟筆為圖片著色。', 'color', 'dance', 'cook', 'listen', 'color 作為動詞時，表示著色或上色。', '想像用彩色筆 color pencils 在畫畫的動作就是 color。', '2026-07-07 05:12:47', '2026-07-07 05:12:47'),
('08042ba1-1351-52fa-b992-3de4b91d0430', '94656702-4cfc-4313-8f4e-0ea94538389d', 'The test was difficult to a certain ___.', '這場考試在某種程度上很困難。', 'degree', 'amount', 'moment', 'place', 'degree 的字根與 grad (階梯) 有關，用來表示事物進展或狀態的程度。', '可以把 degree 想像成爬樓梯時的一階一階，每一階就代表一個程度的變化。', '2026-07-07 03:16:17', '2026-07-07 03:16:17'),
('82aee645-2627-5483-a23c-4f5ad27351e8', '10cfb375-7528-4dac-aa0b-12b3a23c445f', 'My family usually has ___ together at 7:00 PM.', '我們全家通常在晚上七點一起吃晚餐。', 'dinner', 'breakfast', 'lunch', 'snack', 'dinner → 晚餐 (名詞)', 'dinner 晚餐，晚上七點吃 dinner。', '2026-07-07 04:35:02', '2026-07-07 04:35:02'),
('7aeb89ef-e3f8-59a3-9bb3-04f1bacdbaf8', 'b5c46ec7-afd1-4dbd-a3a0-66a983dfbf40', 'My grandfather is a ___; he grows rice and vegetables.', '我的祖父是一位農夫；他種植稻米和蔬菜。', 'farmer', 'singer', 'pilot', 'baker', 'farm (農場) + er (人/者)', 'farm (農場) + er (人) → 農夫', '2026-07-07 05:01:06', '2026-07-07 05:01:06'),
('3a4a4453-9d34-5bfb-956d-4cf64b03154c', '1d86e27e-0866-4c5e-8277-4bc91cc8ab5e', '___ building over there is the oldest one in this city.', '那棟建築物是這座城市中最古老的。', 'That', 'Each', 'Some', 'Every', '限定詞/形容詞 (adj.)，用來指稱距離說話者較遠的人或物。', 'That (那個) → 指向遠方。', '2026-07-05 14:26:52', '2026-07-05 14:26:52');
